args:
$pkg='top.azek431.hzzs'
& .\gradlew.bat --console=plain :app:installDebug
if ($LASTEXITCODE -ne 0) {
    throw '安装 Debug APK 失败'
}

adb shell monkey -p $pkg -c android.intent.category.LAUNCHER 1
if ($LASTEXITCODE -ne 0) {
    throw '启动应用失败'
}

Start-Sleep -Seconds 2

$pidText = adb shell pidof $pkg
if ($LASTEXITCODE -ne 0 -or [string]::IsNullOrWhiteSpace($pidText)) {
    throw "找不到应用进程：$pkg"
}

$pid = ($pidText -split '\s+')[0].Trim()

adb forward --remove tcp:8700 2>$null | Out-Null
adb forward tcp:8700 "jdwp:$pid"

if ($LASTEXITCODE -ne 0) {
    throw 'JDWP 转发失败'
}

Write-Host "JDWP 已转发：localhost:8700 -> $pkg / PID $pid"
